# 输入获取
n = int(input())
arr = [input().split() for _ in range(n)]

trans = {}
for send, receive in arr:
    if trans.get(send) is None:
        trans[send] = set()

    if trans.get(receive) is None:
        trans[receive] = set()

    trans[send].add(receive)


# 算法入口
def getResult():
    for s in trans:
        for c in trans[s]:
            if s not in trans[c]:
                return "False"

    return "True"


# 算法调用
print(getResult())
